/**
 * @param x      bottom-left x coordinate
 * @param y      bottom-left y coordinate
 * @param width  width
 * @param height height
 * @return this rectangle for chaining
 */
public RectangleMutant set(float x, float y, float width, float height) {
    this.x = x;
    this.y = y;
    this.width = width;
    this.height = height;
    return this;
}
